// Parse incoming chat message
const data = items[0].json;

const message = {
  sessionId: data.sessionId || `session_${Date.now()}`,
  customerId: data.customerId || 'anonymous',
  customerName: data.customerName || 'Guest',
  customerEmail: data.customerEmail || '',
  messageText: data.message || data.text || '',
  timestamp: new Date().toISOString(),
  context: data.context || {}
};

return [{ json: message }];

// Build comprehensive context for AI
const currentMessage = items[0].json;
const chatHistory = $node['Load Chat History'].json || [];
const knowledgeBase = $node['Load Knowledge Base'].json || [];

// Format chat history
const conversationHistory = chatHistory.slice(-10).map(msg => {
  return `${msg.role}: ${msg.content}`;
}).join('\n');

// Create context about business
const businessContext = `
Business Name: ${process.env.BUSINESS_NAME}
Website: ${process.env.BUSINESS_WEBSITE}
Phone: ${process.env.BUSINESS_PHONE}
Email: ${process.env.BUSINESS_EMAIL}

We are a travel agency offering various tours and experiences.
`;

// Build knowledge base context
const knowledgeContext = knowledgeBase.map(kb => {
  return `Q: ${kb.question}\nA: ${kb.answer}`;
}).join('\n\n');

return [{
  json: {
    ...currentMessage,
    conversationHistory: conversationHistory,
    businessContext: businessContext,
    knowledgeContext: knowledgeContext
  }
}];

// Extract AI response and prepare for customer
const aiResponse = items[0].json.choices[0].message.content;
const currentMessage = $node['Build AI Context'].json;

// Check if response indicates booking intent
const bookingIntent = aiResponse.toLowerCase().includes('book') || 
                     aiResponse.toLowerCase().includes('reservation') ||
                     aiResponse.toLowerCase().includes('available');

// Check if human handoff needed
const humanHandoff = aiResponse.toLowerCase().includes('transfer to agent') ||
                    aiResponse.toLowerCase().includes('speak with someone');

return [{
  json: {
    sessionId: currentMessage.sessionId,
    customerId: currentMessage.customerId,
    customerName: currentMessage.customerName,
    customerEmail: currentMessage.customerEmail,
    customerMessage: currentMessage.messageText,
    aiResponse: aiResponse,
    bookingIntent: bookingIntent,
    humanHandoff: humanHandoff,
    timestamp: new Date().toISOString(),
    sentiment: 'neutral' // Could add sentiment analysis here
  }
}];

// Analyze chat history to find common questions and patterns
const allChats = items.map(item => item.json);

// Group by similar questions (simplified - in production use embeddings)
const questions = {};

allChats.forEach(chat => {
  if (chat.role === 'user') {
    const normalized = chat.content.toLowerCase().trim();
    if (questions[normalized]) {
      questions[normalized].count++;
    } else {
      questions[normalized] = {
        question: chat.content,
        count: 1,
        responses: []
      };
    }
  }
});

// Find questions asked more than 3 times (frequently asked)
const frequentQuestions = Object.values(questions)
  .filter(q => q.count >= 3)
  .sort((a, b) => b.count - a.count)
  .slice(0, 20);

return [{
  json: {
    totalConversations: allChats.length,
    frequentQuestions: frequentQuestions,
    analyzedAt: new Date().toISOString()
  }
}];
